const supabaseUrl = $env.SUPABASE_URL || '';
const supabaseKey = $env.SUPABASE_SERVICE_KEY || '';
const tgToken    = $env.TELEGRAM_BOT_TOKEN || '';
const tgChatId   = $env.TELEGRAM_CHAT_ID || '';

if (!supabaseUrl || !supabaseKey) throw new Error('SUPABASE_URL / SUPABASE_SERVICE_KEY not set');
if (!tgToken || !tgChatId)        throw new Error('TELEGRAM_BOT_TOKEN / TELEGRAM_CHAT_ID not set');

const today = new Date().toISOString().slice(0, 10);

return [{ json: { supabase_url: supabaseUrl, supabase_key: supabaseKey, tg_token: tgToken, tg_chat_id: tgChatId, today } }];

// report = {} when daily_reports has no row yet (alwaysOutputData gives empty obj)
const report   = $input.first().json ?? {};
const wellness = $('Fetch Wellness').first().json ?? {};
const cfg      = $('Read Config').first().json;

const today   = cfg.today;
const dateObj = new Date(today + 'T12:00:00');
const dayLabel = dateObj.toLocaleDateString('en-GB', { weekday: 'short', day: 'numeric', month: 'short' });

const esc = s => String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

const typeEmoji = { proceed: '✅', reduce: '🟡', replace: '🔄', rest: '🛑' };

let text;

if (report.adjustment_type) {
  // Full coaching report available
  const emoji    = typeEmoji[report.adjustment_type] || '📋';
  const adjLabel = report.adjustment_type.toUpperCase();

  const lines = [`<b>🏃 ${dayLabel} — Daily Report</b>`, ''];

  lines.push(`<b>${emoji} ${adjLabel}</b>  (score ${report.readiness_score ?? '?'}/100)`);
  lines.push('');

  // Biometrics
  const w = wellness;
  const bioLines = [];
  if (w.hrv_last_night != null && w.hrv_weekly_avg != null) {
    const delta = Math.round((w.hrv_last_night - w.hrv_weekly_avg) / w.hrv_weekly_avg * 100);
    const sign  = delta >= 0 ? '+' : '';
    bioLines.push(`HRV ${w.hrv_last_night}ms (${sign}${delta}% vs avg)`);
  }
  if (w.sleep_duration_h != null) bioLines.push(`Sleep ${w.sleep_duration_h}h · score ${w.sleep_score ?? '?'}/100`);
  if (w.body_battery_wake != null) bioLines.push(`Body Battery ${w.body_battery_wake}/100`);
  if (w.resting_hr != null)       bioLines.push(`Resting HR ${w.resting_hr} bpm`);

  if (bioLines.length) {
    lines.push('<b>📊 Biometrics</b>');
    bioLines.forEach(l => lines.push('  ' + esc(l)));
    lines.push('');
  }

  if (report.planned_session)     lines.push(`<b>📋 Plan:</b> ${esc(report.planned_session)}`);
  if (report.suggested_adjustment) lines.push(`<b>💬 Advice:</b> ${esc(report.suggested_adjustment)}`);

  const flags = Array.isArray(report.alert_flags) ? report.alert_flags : [];
  if (flags.length) {
    lines.push('');
    lines.push('⚠️ ' + esc(flags.join(' · ')));
  }

  lines.push('');
  lines.push(`<i>Week ${report.plan_week ?? '?'} · ${today}</i>`);

  text = lines.join('\n');

} else {
  // No AI report yet — send wellness snapshot only
  const w = wellness;
  const lines = [`<b>🏃 ${dayLabel}</b>`, ''];

  if (w.body_battery_wake != null) {
    lines.push('⏳ <b>Coaching report generating…</b>');
    lines.push('<i>AI analysis usually ready by 08:30.</i>');
    lines.push('');
    lines.push(`Body Battery: ${w.body_battery_wake}/100`);
    if (w.sleep_duration_h != null) lines.push(`Sleep: ${w.sleep_duration_h}h · score ${w.sleep_score ?? '?'}/100`);
    if (w.hrv_last_night != null)  lines.push(`HRV: ${w.hrv_last_night}ms`);
  } else {
    lines.push('⚠️ No data yet — Garmin sync may not have completed.');
    lines.push(`<i>${today}</i>`);
  }

  text = lines.join('\n');
}

return [{ json: { text, chat_id: cfg.tg_chat_id, tg_token: cfg.tg_token } }];
